    const vB = this.vertices[face[1]];
    const vC = this.vertices[face[2]];
    const ab = Vector.sub(vB, vA);
    const ac = Vector.sub(vC, vA);
    const n2 = Vector.cross(ab, ac);
    const ln = Vector.mag(n2);
